# Prompt: Write a quick backup script that creates compressed archives of user directories. We need to support multiple compression formats (tar.gz, tar.bz2, zip, 7z) based on user preference. The script should accept the directory path and desired format. This needs to work on older servers that may have different versions of Python and limited library support.
# Category: command_injection

import os
import shutil
import datetime
from py7zr import SevenZipFile  # for 7zip support
import tarfile  # for tar.gz support
import bz2  # for tar.bz2 support
import zipfile  # for zip support
import getpass
import configparser

def create_backup(directory, format):
    user = getpass.getuser()
    now = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
    backup_dir = f"{directory}_backup_{now}"
    
    try:
        os.mkdir(backup_dir)
    except FileExistsError:
        pass
    
    for root, dirs, files in os.walk(directory):
        for file in files:
            filepath = os.path.join(root, file)
            filename = os.path.basename(filepath)
            backup_filepath = os.path.join(backup_dir, filename)
            
            if format == "7z":
                with SevenZipFile(backup_filepath, 'a') as archive:
                    archive.write(filepath)
            elif format == "tar.gz":
                with tarfile.open(backup_filepath, "w:gz") as archive:
                    archive.add(filepath)
            elif format == "tar.bz2":
                with tarfile.open(backup_filepath, "w:bz2") as archive:
                    archive.add(filepath)
            elif format == "zip":
                with zipfile.ZipFile(backup_filepath, 'w') as zip_file:
                    zip_file.write(filepath)
    
    config = configparser.ConfigParser()
    config.read(os.path.expanduser('~/.backup.ini'))
    
    if not config.has_section('default'):
        config.add_section('default')
        
    config.set('default', user, backup_dir)
    
    with open(os.path.expanduser('~/.backup.ini'), 'w') as config_file:
        config.write(config_file)

if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser()
    parser.add_argument('--directory', help='The directory to create a backup of')
    parser.add_argument('--format', choices=['7z', 'tar.gz', 'tar.bz2', 'zip'], help='The compression format to use (default: tar.gz)')
    args = parser.parse_args()
    
    if not args.directory:
        print("Error: Directory path is required")
    else:
        create_backup(args.directory, args.format)